const row = $input.first().json;
let anchorDate = row.last_sync;
if (!anchorDate) {
    const fallback = new Date();
    fallback.setHours(fallback.getHours() - 1);
    anchorDate = fallback.toISOString();
}
const d = new Date(anchorDate);
if (isNaN(d.getTime())) {
  throw new Error('无效日期: ' + String(anchorDate).substring(0, 30));
}
const pad = (n) => n < 10 ? '0' + n : n;
const formatted = `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
// 安全: 严格日期格式校验 (防 SQL 注入)
if (!/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(formatted)) {
  throw new Error('日期格式异常: ' + formatted);
}
return { json: { last_date: formatted } };

const items = $input.all();
const companyCode = $env.DP_COMPANY_CODE || 'DEFAULT';
const batchSize = 200;
const batches = [];
const esc = (v) => { if(v===null||v===undefined) return ''; let s=String(v).substring(0,500); s=s.replace(/\0/g,''); return s.replace(/'/g,"''"); };
const escInt = (v) => { const n = parseInt(v); return isNaN(n) ? 'NULL' : String(n); };
const cc = esc(companyCode);
for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);
  const values = batch.map(r => {
    const j = r.json;
    return `('${cc}','${esc(j.ItemCode)}','${esc(j.ItemName)}','${esc(j.InvntryUom)}','${esc(j.ManBtchNum)||'N'}',NOW(),'${esc(j.ForeignName)}',${escInt(j.ItemGroup)},'${esc(j.InvntryUom)}','${esc(j.PurchaseUom)}','${esc(j.SellUom)}','${esc(j.IsActive)||'Y'}')`;
  }).join(',\n');
  const sql = `INSERT INTO wms.wms_items_cache (company_code, item_code, item_name, uom, man_batch_num, synced_at, foreign_name, item_group, inventory_uom, purchase_uom, sell_uom, is_active) VALUES ${values} ON CONFLICT (company_code, item_code) DO UPDATE SET item_name=EXCLUDED.item_name, uom=EXCLUDED.uom, man_batch_num=EXCLUDED.man_batch_num, synced_at=NOW(), foreign_name=EXCLUDED.foreign_name, item_group=EXCLUDED.item_group, inventory_uom=EXCLUDED.inventory_uom, purchase_uom=EXCLUDED.purchase_uom, sell_uom=EXCLUDED.sell_uom, is_active=EXCLUDED.is_active`;
  batches.push({ json: { sql, batch_num: Math.floor(i/batchSize)+1, count: batch.length } });
}
if (batches.length === 0) return [{ json: { sql: 'SELECT 1', batch_num: 0 } }];
return batches;

// V1.1: 统计实际同步条数 — 从生成节点获取每批行数 (修复批数≠条数)
const batches = $('生成批量UPSERT').all();
let totalRows = 0;
batches.forEach(b => {
  totalRows += (b.json.count || 0);
});
const batchCount = batches.length;
return { json: { success: true, count: totalRows, message: '物料缓存增量同步: ' + totalRows + ' 条 (' + batchCount + ' 批) 写入PG' } };
